(6, 'mohamedsuleyman813@gmail.com', '<span style=\"background-color:#ff6b6b; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Cabdiraxmaan <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">PER</small></span> <span style=\"background-color:#ff6b6b; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Axmed <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">PER</small></span> oo ka shaqeeya ururka Hormuud <span style=\"background-color:#ffd43b; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Foundation <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">ORG</small></span> ayaa ku nool magaalada <span style=\"background-color:#4dabf7; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Muqdisho <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">LOC</small></span>, gaar ahaan <span style=\"background-color:#4dabf7; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">degmada <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">LOC</small></span> Hodan. Maalin kasta wuxuu u shaqo tagaa xafiiska shirkadda Hormuud Telecom, halkaas oo uu ka qabto howlaha maamulka iyo adeegyada bulshada. <span style=\"background-color:#ff6b6b; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Cabdiraxmaan <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">PER</small></span> wuxuu sidoo kale la shaqeeyaa hay’adda <span style=\"background-color:#ffd43b; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">UNICEF <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">ORG</small></span> si uu uga qayb qaato mashruucyo waxbarasho oo lagu taageerayo carruurta ku nool gobolka <span style=\"background-color:#4dabf7; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">Banaadir <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">LOC</small></span>. Sannadkii <span style=\"background-color:#63e6be; border:2px solid white; border-radius:6px; padding:2px 6px; margin:1px; color:black;\">2025 <small style=\"font-weight:bold; border:1px solid white; padding: 2px 4px; color: white\">DATE</small></span>,', NULL, NULL, '2026-03-24 09:59:10'),
